from dataclasses import dataclass
from enum import Enum
from opentelemetry import metrics
import threading


class BudgetState(Enum):
    NORMAL = "normal"
    WARNING = "warning"     # 80% consumed
    CRITICAL = "critical"   # 95% consumed
    EXHAUSTED = "exhausted" # 100% consumed


@dataclass
class SpendBudget:
    daily_limit_usd: float
    monthly_limit_usd: float
    current_daily_usd: float = 0.0
    current_monthly_usd: float = 0.0
    _lock: threading.Lock = None

    def __post_init__(self):
        self._lock = threading.Lock()

    def add_spend(self, amount_usd: float) -> BudgetState:
        with self._lock:
            self.current_daily_usd += amount_usd
            self.current_monthly_usd += amount_usd
        return self.state()

    def state(self) -> BudgetState:
        daily_pct = self.current_daily_usd / self.daily_limit_usd
        monthly_pct = self.current_monthly_usd / self.monthly_limit_usd
        worst = max(daily_pct, monthly_pct)
        if worst >= 1.0:
            return BudgetState.EXHAUSTED
        elif worst >= 0.95:
            return BudgetState.CRITICAL
        elif worst >= 0.80:
            return BudgetState.WARNING
        return BudgetState.NORMAL

    def should_throttle(self) -> bool:
        return self.state() in {BudgetState.CRITICAL, BudgetState.EXHAUSTED}

    def should_block(self) -> bool:
        return self.state() == BudgetState.EXHAUSTED


def request_handler(budget: SpendBudget, request: dict) -> dict:
    if budget.should_block():
        return {"error": "spend_budget_exhausted",
                "message": "Daily GenAI spend limit reached. Service resumes at midnight UTC."}

    if budget.should_throttle():
        # Downgrade to a cheaper model rather than returning an error
        request["model"] = "gpt-4o-mini"   # cheapest available fallback

    # ... proceed with request
    return {"status": "ok"}
